patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 6846f13dced66..de05e3b73f519 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -2096,7 +2096,8 @@ static FPClassTest adjustDemandedMaskFromFlags(FPClassTest DemandedMask,

 /// Apply epilog fixups to a floating-point intrinsic. See if the result can
 /// fold to a constant, or apply fast math flags.
-static Value *simplifyDemandedFPClassResult(CallInst *FPOp, FastMathFlags FMF,
+static Value *simplifyDemandedFPClassResult(Instruction *FPOp,
+                                            FastMathFlags FMF,
                                             FPClassTest DemandedMask,
                                             KnownFPClass &Known,
                                             ArrayRef<KnownFPClass> KnownSrcs) {
@@ -2660,8 +2661,8 @@ Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Instruction *I,
     Known = KnownFPClass::fpext(KnownSrc, DstTy, SrcTy);
     Known.knownNot(~DemandedMask);

-    return getFPClassConstant(VTy, Known.KnownFPClasses,
-                              /*IsCanonicalizing=*/true);
+    return simplifyDemandedFPClassResult(I, FMF, DemandedMask, Known,
+                                         {KnownSrc});
   }
   case Instruction::Call: {
     CallInst *CI = cast<CallInst>(I);

tests.test_body:
define nofpclass(nan zero sub norm) float @ret_only_inf__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

define nofpclass(nan inf sub norm) float @ret_only_zero__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

declare nofpclass(nan inf sub norm) half @returns_zero_f16()

define nofpclass(snan) float @ret_no_snan__fpext__always_zero() {
  %zero = call half @returns_zero_f16()
  %result = fpext half %zero to float
  ret float %result
}

define nofpclass(nan ninf zero sub norm) float @ret_only_pinf__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

declare nofpclass(nan zero sub norm) half @returns_inf_f16()

define nofpclass(snan) float @ret_no_snan__fpext__always_inf() {
  %inf = call half @returns_inf_f16()
  %result = fpext half %inf to float
  ret float %result
}

declare nofpclass(inf sub norm) half @returns_zero_or_nan_f16()

define nofpclass(snan) float @ret_no_snan__fpext__always_zero_or_nan() {
  %zero.or.nan = call half @returns_zero_or_nan_f16()
  %result = fpext half %zero.or.nan to float
  ret float %result
}

define nofpclass(qnan inf zero sub norm) float @ret_only_snan__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

define nofpclass(nan inf zero psub norm) float @ret_only_nsub__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

define nofpclass(nan inf norm) float @ret_only_sub_zero__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}

define nofpclass(inf zero sub norm) float @ret_only_nan__fpext(half %x) {
  %result = fpext half %x to float
  ret float %result
}
